// src/pages/shared/ReportPage.jsx
import { useState, useEffect } from "react";
import { reportAPI, taskAPI } from "../../utils/api";
import { StatusBadge } from "../../components/shared/index.jsx";
import { formatMinutes } from "../../utils/helpers";
import { useAuth } from "../../hooks/useAuth";

const TARGET_MINS = 30 * 60;

export default function ReportPage() {
  const { user }   = useAuth();
  const [summary,  setSummary]  = useState(null);
  const [projects, setProjects] = useState([]);
  const [tasks,    setTasks]    = useState([]);
  const [loading,  setLoading]  = useState(true);

  useEffect(() => {
    Promise.all([reportAPI.summary(), reportAPI.projects(), taskAPI.getAll()])
      .then(([s, p, t]) => {
        setSummary(s.summary);
        setProjects(p.report || []);
        setTasks(t.tasks || []);
        setLoading(false);
      }).catch(() => setLoading(false));
  }, []);

  if (loading) return <div style={{ padding:60, textAlign:"center" }}><div className="spinner"/></div>;

  const weekPct  = summary ? Math.min(100, Math.round((summary.weekMins || 0) / TARGET_MINS * 100)) : 0;
  const weekColor = weekPct >= 100 ? "#16a34a" : weekPct >= 60 ? "#1d4ed8" : "#d97706";

  return (
    <div className="animate-fadeUp">

      {/* Weekly hours highlight */}
      {summary && (
        <div className="card mb-24" style={{ borderTop:`4px solid ${weekColor}` }}>
          <div className="card-header">
            <div className="card-title">⏱ Weekly Hours — {summary.weekKey}</div>
            <span style={{ fontSize:11, fontWeight:700, padding:"3px 10px", borderRadius:99, background: weekPct>=100?"#dcfce7":weekPct>=60?"#dbeafe":"#fef3c7", color:weekPct>=100?"#166534":weekPct>=60?"#1e40af":"#92400e" }}>
              {weekPct}%
            </span>
          </div>
          <div className="card-body">
            <div style={{ display:"flex", justifyContent:"space-between", marginBottom:8 }}>
              <span style={{ fontSize:13, color:"#6b7280" }}>
                {user.role === "intern" ? "Your" : "System"} weekly progress toward 30h target
              </span>
              <span style={{ fontWeight:700, fontSize:14 }}>
                {formatMinutes(summary.weekMins || 0)} / 30h
              </span>
            </div>
            <div style={{ height:12, background:"#f1f5f9", borderRadius:6, overflow:"hidden", marginBottom:8 }}>
              <div style={{ height:"100%", width:weekPct+"%", background:`linear-gradient(90deg,${weekColor},${weekColor}99)`, borderRadius:6, transition:"width .5s" }}/>
            </div>
            <p style={{ fontSize:12, fontWeight:600, color:weekColor }}>
              {weekPct >= 100
                ? "✅ Weekly target met!"
                : `⚡ ${formatMinutes(Math.max(0, TARGET_MINS - (summary.weekMins||0)))} more to reach 30h weekly goal`}
            </p>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:12, marginTop:16, textAlign:"center" }}>
              {[
                ["This week tasks", summary.weekTasks || 0, "#0a2e1a"],
                ["This week hours", formatMinutes(summary.weekMins||0), weekColor],
                ["Total hours",     formatMinutes(summary.totalMins),   "#0a2e1a"],
              ].map(([l,v,c]) => (
                <div key={l} style={{ background:"#f8fafc", borderRadius:10, padding:"12px 8px" }}>
                  <div style={{ fontFamily:"Syne,sans-serif", fontWeight:800, fontSize:20, color:c }}>{v}</div>
                  <div style={{ fontSize:11, color:"#9ca3af", fontWeight:600, textTransform:"uppercase", letterSpacing:".5px", marginTop:3 }}>{l}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <div className="grid-2 mb-24">
        {/* Summary */}
        {summary && (
          <div className="week-summary">
            <h3>📊 {user.role==="intern" ? "My Report" : "Overall Report"}</h3>
            {[
              ["Total Tasks",     summary.total,                              "good"],
              ["Completed",       summary.done,                               "good"],
              ["In Progress",     summary.inProgress,                         "warn"],
              ["On Hold",         summary.hold,                               "warn"],
              ["To Do",           summary.todo,                               ""],
              ["Total Hours",     formatMinutes(summary.totalMins),           "good"],
              ["Completion Rate", `${summary.pct}%`, summary.pct>=70?"good":"warn"],
            ].map(([l,v,c]) => (
              <div key={l} className="week-stat">
                <span className="week-stat-label">{l}</span>
                <span className={`week-stat-val${c?" "+c:""}`}>{v}</span>
              </div>
            ))}
          </div>
        )}
        {/* By project */}
        <div className="card">
          <div className="card-header"><div className="card-title">By Project</div></div>
          <div className="card-body">
            {projects.map(p => (
              <div key={p._id||p.id} style={{ marginBottom:20 }}>
                <div className="flex justify-between mb-8">
                  <span style={{ fontSize:13, fontWeight:600 }}>{p.icon} {p.name}</span>
                  <span className="text-xs text-gray">{p.stats.total} tasks · {formatMinutes(p.stats.totalMins)}</span>
                </div>
                <div className="progress-bar">
                  <div className="progress-fill" style={{ width:(summary?.total?(p.stats.total/summary.total*100):0)+"%" }}/>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Full log */}
      <div className="card">
        <div className="card-header">
          <div className="card-title">📄 Full Task Log</div>
          <span className="text-sm text-gray">{tasks.length} records</span>
        </div>
        <div className="table-wrap">
          {tasks.length === 0 ? (
            <div className="empty-state"><div className="empty-icon">📭</div><h3>No records</h3></div>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Date</th><th>Project</th>
                  {user.role !== "intern" && <th>Intern</th>}
                  <th>Task</th><th>Sub-tasks</th><th>Status</th><th>Hours</th><th>Checked By</th>
                </tr>
              </thead>
              <tbody>
                {tasks.map(t => (
                  <tr key={t._id||t.id}>
                    <td className="text-sm text-gray">{t.date}</td>
                    <td><span className="tag">{t.project}</span></td>
                    {user.role !== "intern" && <td className="text-sm">{(t.assignedTo?.name||"").split(" ")[0]||"–"}</td>}
                    <td className="text-sm" style={{ maxWidth:220 }}>{t.task}</td>
                    <td>
                      {(t.subTasks||[]).length > 0
                        ? <span style={{ fontSize:11, fontWeight:700, background:"#eff6ff", color:"#1d4ed8", padding:"2px 8px", borderRadius:99, border:"1px solid #bfdbfe" }}>
                            {(t.subTasks||[]).filter(s=>s.status==="Done").length}/{(t.subTasks||[]).length}
                          </span>
                        : <span style={{ fontSize:12, color:"#d1d5db" }}>—</span>}
                    </td>
                    <td><StatusBadge status={t.status}/></td>
                    <td className="text-sm text-bold">{t.totalMinutes}</td>
                    <td>{(t.adminChecked||[]).map(u => <span key={u} className="chip" style={{ fontSize:10, marginRight:3 }}>{u}</span>)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}
